// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Outlet) predicate.Outlet {
	return predicate.Outlet(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Outlet) predicate.Outlet {
	return predicate.Outlet(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Outlet) predicate.Outlet {
	return predicate.Outlet(sql.NotPredicates(p))
}
